pub use aspace::mmap::{MmapFlags, MmapIO, MmapPerm};
pub use shm::{
    IPC_CREAT, IPC_EXCL, IPC_PRIVATE, IPC_RMID, ShmError, ShmSegment, shm_at, shm_ctl, shm_dt,
    shm_get,
};

use axerrno::{AxError, AxResult};
use axhal::mem::phys_to_virt;
use kspin::SpinNoIrq;
use lazyinit::LazyInit;
pub use memory_addr::{PhysAddr, VirtAddr, va};
use memory_set::MappingError;

static KERNEL_ASPACE: LazyInit<SpinNoIrq<AddrSpace>> = LazyInit::new();

fn mapping_err_to_ax_err(err: MappingError) -> AxError {
    warn!("Mapping error: {:?}", err);
    match err {
        MappingError::InvalidParam => AxError::InvalidInput,
        MappingError::AlreadyExists => AxError::AlreadyExists,
        MappingError::BadState => AxError::BadState,
    }
}

/// Creates a new address space for kernel itself.
pub fn new_kernel_aspace() -> AxResult<AddrSpace> {
    let mut aspace = AddrSpace::new_empty(
        va!(axconfig::plat::KERNEL_ASPACE_BASE),
        axconfig::plat::KERNEL_ASPACE_SIZE,
    )?;
    for r in axhal::mem::memory_regions() {
        aspace.map_linear(phys_to_virt(r.paddr), r.paddr, r.size, r.flags.into())?;
    }
    Ok(aspace)
}

/// Returns the globally unique kernel address space.
pub fn kernel_aspace() -> &'static SpinNoIrq<AddrSpace> {
    &KERNEL_ASPACE
}

/// Returns the root physical address of the kernel page table.
pub fn kernel_page_table_root() -> PhysAddr {
    KERNEL_ASPACE.lock().page_table_root()
}

/// Initializes virtual memory management.
///
/// It mainly sets up the kernel virtual memory address space and recreate a
/// fine-grained kernel page table.
pub fn init_memory_management() {
    info!("Initialize virtual memory management...");

    let kernel_aspace = new_kernel_aspace().expect("failed to initialize kernel address space");
    debug!("kernel address space init OK: {:#x?}", kernel_aspace);
    KERNEL_ASPACE.init_once(SpinNoIrq::new(kernel_aspace));
    axhal::paging::set_kernel_page_table_root(kernel_page_table_root());
}

/// Initializes kernel paging for secondary CPUs.
pub fn init_memory_management_secondary() {
    axhal::paging::set_kernel_page_table_root(kernel_page_table_root());
}

use axerrno::{AxError, AxResult, ax_err};
use axhal::mem::phys_to_virt;
use axhal::paging::{MappingFlags, PageTable, PagingError};
use core::fmt;
use memory_addr::{
    FrameTracker, MemoryAddr, PAGE_SIZE_4K, PageIter4K, PhysAddr, VirtAddr, VirtAddrRange,
    is_aligned_4k,
};
use memory_set::{MappingBackend, MemoryArea, MemorySet};
use page_table_multiarch::PageSize;

#[cfg(feature = "mmap")]
pub mod mmap;

use crate::backend::frame::FrameTrackerRef;
use crate::backend::{Backend, VmAreaType};
use crate::heap::HeapSpace;
use crate::mapping_err_to_ax_err;

/// The virtual memory address space.
pub struct AddrSpace {
    va_range: VirtAddrRange,
    pub areas: MemorySet<Backend>,
    pub(crate) pt: PageTable,
    #[cfg(feature = "heap")]
    pub(crate) heap: Option<HeapSpace>,
}

impl AddrSpace {
    /// Returns the address space base.
    pub const fn base(&self) -> VirtAddr {
        self.va_range.start
    }

    /// Returns the address space end.
    pub const fn end(&self) -> VirtAddr {
        self.va_range.end
    }

    /// Returns the address space size.
    pub fn size(&self) -> usize {
        self.va_range.size()
    }

    /// Returns the reference to the inner page table.
    pub const fn page_table(&mut self) -> &mut PageTable {
        &mut self.pt
    }

    /// Returns the root physical address of the inner page table.
    pub const fn page_table_root(&self) -> PhysAddr {
        self.pt.root_paddr()
    }

    /// Checks if the address space contains the given address range.
    pub fn contains_range(&self, start: VirtAddr, size: usize) -> bool {
        self.va_range
            .contains_range(VirtAddrRange::from_start_size(start, size))
    }

    /// Creates a new empty address space.
    pub fn new_empty(base: VirtAddr, size: usize) -> AxResult<Self> {
        Ok(Self {
            va_range: VirtAddrRange::from_start_size(base, size),
            areas: MemorySet::new(),
            pt: PageTable::try_new().map_err(|_| AxError::NoMemory)?,
            #[cfg(feature = "heap")]
            heap: None,
        })
    }

    pub fn new_empty_like(other: &AddrSpace) -> AxResult<Self> {
        Ok(Self {
            va_range: other.va_range,
            areas: MemorySet::new(),
            pt: PageTable::try_new().map_err(|_| AxError::NoMemory)?,
            #[cfg(feature = "heap")]
            heap: None,
        })
    }

    pub fn filter_areas<F>(
        &mut self,
        filter_fn: F,
    ) -> core::iter::Filter<impl Iterator<Item = &mut MemoryArea<Backend>>, F>
    where
        F: FnMut(&&mut MemoryArea<Backend>) -> bool,
    {
        self.areas.iter_mut().filter(filter_fn)
    }

    pub fn find_frame(&self, vaddr: VirtAddr) -> Option<FrameTrackerRef> {
        self.areas.find_frame(vaddr)
    }

    /// Remap a vaddr to a new frame.pub fn remap_frame(&mut self, vaddr:
    /// B::Addr, new_frame: B::FrameTrackerImpl) {
    pub fn remap(
        &mut self,
        vaddr: VirtAddr,
        new_frame: <Backend as MappingBackend>::FrameTrackerRef,
        new_flags: MappingFlags,
    ) -> bool {
        //self.areas.remap_frame(vaddr, new_frame);
        self.pt
            .remap(vaddr, new_frame.pa, new_flags)
            .map(|(_, tlb)| tlb.flush())
            .is_ok()
            .then(|| {
                let vaddr = vaddr.align_down_4k();

                trace!(
                    "Trying to remap frame tracker {:?} to {:?}.",
                    vaddr, new_frame
                );
                self.areas.remap_frame(vaddr, new_frame);
                true
            })
            .unwrap_or(false)
    }

    /// Copies page table mappings from another address space.
    ///
    /// It copies the page table entries only rather than the memory regions,
    /// usually used to copy a portion of the kernel space mapping to the
    /// user space.
    ///
    /// Note that on dropping, the copied PTEs will also be cleared, which could
    /// taint the original page table. For workaround, you can use
    /// [`AddrSpace::clear_mappings`].
    ///
    /// Returns an error if allow_overlap is false and the two address spaces overlap.
    pub fn copy_mappings_from(&mut self, other: &AddrSpace, allow_overlap: bool) -> AxResult {
