fn handle_breakpoint(era: &mut usize) {
    debug!("Exception(Breakpoint) @ {:#x} ", era);
    *era += 4;
}

fn handle_page_fault(tf: &TrapFrame, mut access_flags: MappingFlags, is_user: bool) {
    if is_user {
        access_flags |= MappingFlags::USER;
    }
    let vaddr = va!(badv::read().raw());
    if !handle_trap!(PAGE_FAULT, vaddr, access_flags, is_user) {
        panic!(
            "Unhandled {} Page Fault @ {:#x}, fault_vaddr={:#x} ({:?}):\n{:#x?}",
            if is_user { "PLV3" } else { "PLV0" },
            tf.era,
            vaddr,
            access_flags,
            tf,
        );
    }
}

#[unsafe(no_mangle)]
fn loongarch64_trap_handler(tf: &mut TrapFrame, from_user: bool) {
    pre_trap(tf, from_user);
    let estat = estat::read();
    let trap = estat.cause();

    trace!("trap from {:x?}", tf.get_ip());
    if matches!(trap, Trap::Exception(_)) {
        unmask_irqs(tf);
    }

    match trap {
        #[cfg(feature = "uspace")]
        Trap::Exception(Exception::Syscall) => {
            tf.era += 4;
            tf.regs.a0 = crate::trap::handle_syscall(tf, tf.regs.a7) as usize;
        }
        Trap::Exception(Exception::LoadPageFault)
        | Trap::Exception(Exception::PagePrivilegeIllegal)
        | Trap::Exception(Exception::PageNonReadableFault) => {
            handle_page_fault(tf, MappingFlags::READ, from_user);
        }
        Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::PageModifyFault) => {
            handle_page_fault(tf, MappingFlags::WRITE, from_user);
        }
        Trap::Exception(Exception::FetchPageFault)
        | Trap::Exception(Exception::PageNonExecutableFault) => {
            handle_page_fault(tf, MappingFlags::EXECUTE, from_user);
        }
        Trap::Exception(Exception::Breakpoint) => {
            handle_breakpoint(&mut tf.era);
        }
        Trap::Exception(Exception::AddressNotAligned) => unsafe { emulate_load_store_insn(tf) },
        Trap::Interrupt(_) => {
            let irq_num: usize = estat.is().trailing_zeros() as usize;
            handle_trap!(IRQ, irq_num);
        }
        _ => {
            panic!(
                "Unhandled trap {:?} @ {:#x}:\n{:#x?}",
                estat.cause(),
                tf.era,
                tf
            );
        }
    }
    post_trap(tf, from_user);
    mask_irqs();
}

// Interrupt unmasking function for exception handling.
// NOTE: It must be invoked after the switch to kernel mode has finished
//
// If interrupts were enabled before the exception (`PIE` bit in `PRMD` is set),
// re-enable interrupts before handling the exception.
//
// On loongarch64, when an exception is triggered, records the old value of
// `IE` domain in `CSR.CRMD` in `PIE` domain in `PRMD`. When the `ERTN`
// instruction is executed to return from the exception handler, the hardware
// restores the value of the `PIE` domain to the `IE` domain of `CSR.CRMD`.
fn unmask_irqs(tf: &TrapFrame) {
    const PIE: usize = 1 << 2;
    if tf.prmd & PIE == PIE {
        super::enable_irqs();
    } else {
        debug!("Interrupts were disabled before exception");
    }
}

fn mask_irqs() {
    super::disable_irqs();
}

use core::{ffi::c_int, ptr::null_mut, time::Duration};

use arceos_posix_api::{
    FdSets,
    ctypes::{self, FD_SETSIZE},
    syscall_body, zero_fd_set,
};
use axerrno::{LinuxError, LinuxResult};
use axhal::time::monotonic_time;
use axtask::{current, yield_now, TaskExtRef};
use linux_raw_sys::general::*;

use crate::task::sys_sigprocmask;

pub unsafe fn sys_pselect(
    nfds: c_int,
    readfds: *mut ctypes::fd_set,
    writefds: *mut ctypes::fd_set,
    exceptfds: *mut ctypes::fd_set,
    timeout: *const ctypes::timespec,
    sigmask: *const sigset_t,
) -> LinuxResult<isize> {
    debug!(
        "sys_pselect <= {} {:#x} {:#x} {:#x}",
        nfds, readfds as usize, writefds as usize, exceptfds as usize
    );

    // 1. 参数验证
    if nfds < 0 {
        return Err(LinuxError::EINVAL);
    }
    let nfds = (nfds as usize).min(FD_SETSIZE as usize);

    // 2. 处理信号掩码（原子性修改）
    let old_sigmask = if !sigmask.is_null() {
        let new_mask = unsafe { *sigmask };
        Some(sys_sigprocmask(SIG_SETMASK as i32, sigmask, null_mut())?)
    } else {
        None
    };

    // 3. 处理超时
    let deadline = if !timeout.is_null() {
        let ts = unsafe { timeout.as_ref().ok_or(LinuxError::EFAULT)? };
        // 检查立即返回的特殊情况（timeout=0）
        if ts.tv_sec == 0 && ts.tv_nsec == 0 {
            // 立即返回，不阻塞
            let res = unsafe {
                zero_fd_set(readfds, nfds);
                zero_fd_set(writefds, nfds);
                zero_fd_set(exceptfds, nfds);
                FdSets::from(nfds, readfds, writefds, exceptfds)
                    .poll_all(readfds, writefds, exceptfds)?
            };

            // 恢复信号掩码
            if let Some(old_mask) = old_sigmask {
                sys_sigprocmask(SIG_SETMASK as i32, &old_mask as *const _ as _, null_mut())?;
            }

            return Ok(res as isize);
        }
        Some(monotonic_time() + Duration::new(ts.tv_sec as u64, ts.tv_nsec as u32))
    } else {
        None // 无限等待
    };

    // 4. 主循环
    let fd_sets = FdSets::from(nfds, readfds, writefds, exceptfds);
    unsafe {
        zero_fd_set(readfds, nfds);
        zero_fd_set(writefds, nfds);
        zero_fd_set(exceptfds, nfds);
    }

    loop {
        #[cfg(feature = "net")]
        axnet::poll_interfaces();

        let res = fd_sets.poll_all(readfds, writefds, exceptfds)?;
        if res > 0 {
            // 恢复信号掩码
            if let Some(old_mask) = old_sigmask {
                sys_sigprocmask(SIG_SETMASK as i32, &old_mask as *const _ as _, null_mut())?;
            }
            return Ok(res as isize);
        }

        // 检查超时
        if let Some(deadline) = deadline {
            if monotonic_time() >= deadline {
                // 恢复信号掩码
                if let Some(old_mask) = old_sigmask {
                    sys_sigprocmask(SIG_SETMASK as i32, &old_mask as *const _ as _, null_mut())?;
                }
                return Ok(0);
            }
        }

        // 检查是否有待处理的信号
        if let Some(old_mask) = old_sigmask {
            let curr = current();
            if curr.task_ext().process_data().signal.lock().has_pending() {
                // 恢复信号掩码
                sys_sigprocmask(SIG_SETMASK as i32, &old_mask as *const _ as _, null_mut())?;
                return Err(LinuxError::EINTR);
            }
        }

        // 让出CPU
        yield_now();
    }
}

